import type { Dayjs } from "dayjs";

import type { BwCashflowModel } from "@dfp/bw-sdk-bw-cashflow";

import type { Interval } from "../utils/formatPeriodLabel.ts";

/**
 * Chart view modes for the cashflow visualization
 * - bar: Bar chart showing income vs costs
 * - line: Line chart showing balance progression
 */
export type ChartViewMode = "bar" | "line";

export type { Interval };

export type Currency = NonNullable<
  BwCashflowModel["getCashFlowAndBalanceStates"]["request"]["filtering"]["currency"]
>;

/**
 * Category sum for income or costs
 */
export type CategorySum = {
  category: string;
  amount: number;
};

/**
 * Balance state object from API
 */
export interface BalanceState {
  balance: number;
  date?: string;
}

/**
 * Cash flow interval from API response
 */
export type CashFlowInterval = {
  dateFrom: string;
  dateTo: string;
  costs: number;
  income: number;
  netChange: number;
  startedBalance?: BalanceState;
  finalBalance?: BalanceState;
  incomeCategorySum?: CategorySum[];
  costsCategorySum?: CategorySum[];
  transactionCount?: number;
  cumulativeCosts?: number;
  cumulativeIncome?: number;
  cumulativeNetChange?: number;
};

/**
 * Balance quality indicator
 */
export type BalanceQuality = "IMPORTED" | "DERIVED" | "CALCULATED";

/**
 * Balance point from API response
 */
export type BalancePoint = {
  balance: number;
  date?: string;
  balanceQuality?: BalanceQuality;
};

/**
 * Transformed data point for bar chart visualization
 */
export type BarChartDataPoint = {
  // Display label for the period
  period: string;
  // Unique identifier for synchronization (e.g., "2025-01-01_2025-01-31")
  periodKey: string;
  dateFrom: string;
  dateTo: string;
  income: number;
  costs: number;
  netChange: number;
  incomePlanned?: number;
  costsPlanned?: number;
  incomeCategories?: CategorySum[];
  costsCategories?: CategorySum[];
  transactionCount?: number;
};

/**
 * Transformed data point for line chart visualization
 */
export type LineChartDataPoint = {
  [key: string]: number | string | undefined;
  // ISO date string
  date: string;
  // Numeric timestamp for proper x-axis spacing
  timestamp: number;
  dateLabel: string;
  balance: number;
  // Link to corresponding bar chart period for synchronization
  periodKey: string;
  balanceQuality: BalanceQuality;
};

/**
 * Legend data for displaying current balance and account info
 */
export type LegendData = {
  /** Current total balance across all selected accounts */
  currentBalance: number | null;
  /** Currency code (e.g., "EUR", "CZK") */
  currency: string;
  /** Number of bank accounts included in the data */
  bankAccountCount: number;
  /** Quality of the most recent balance point */
  balanceQuality?: BalanceQuality;
};

/**
 * Time period controls for navigating and selecting periods
 */
export type TimePeriodControlsType = {
  /** Currently selected day that determines the highlighted period */
  selectedDay: Dayjs;
  /** Select a specific day (from date picker). Optionally update interval atomically. */
  setPeriod: (day: Dayjs, newInterval?: Interval) => void;
  /** Navigate to previous period */
  goToPreviousPeriod: () => void;
  /** Navigate to next period */
  goToNextPeriod: () => void;
  /** Whether we can navigate to previous period (not at min date) */
  canGoToPreviousPeriod: boolean;
  /** Whether we can navigate to next period (not at max date) */
  canGoToNextPeriod: boolean;
  /** Minimum selectable date (from settings - oldest transaction) */
  maxDateRangeFrom: Dayjs;
  /** Maximum selectable date (current date + 5 months) */
  maxDateRangeTo: Dayjs;
};

/**
 * Context type for cashflow chart state and data
 */
export type CashflowChartContextType = {
  viewMode: ChartViewMode;
  setViewMode: (mode: ChartViewMode) => void;
  interval: Interval;
  setInterval: (interval: Interval) => void;
  barChartData: BarChartDataPoint[];
  lineChartData: LineChartDataPoint[];
  lineChartSegmentKeys: {
    calculatedSegmentKeys: string[];
    importedSegmentKeys: string[];
    derivedSegmentKeys: string[];
  };
  legendData: LegendData;
};

import type { BwCashflowModel } from "@dfp/bw-sdk-bw-cashflow";

export type CashFlowResponse =
  BwCashflowModel["getCashFlowAndBalanceStates"]["response"];
type CashFlowStates = NonNullable<CashFlowResponse["cashFlowStates"]>;
type SumArray = NonNullable<CashFlowStates["sumArray"]>;
type SumArrayItem = SumArray[number];
type IncomeCategorySum = NonNullable<SumArrayItem["incomeCategorySum"]>;
type ApiCategoryType = IncomeCategorySum[number]["category"];

export type CategoryType = ApiCategoryType;

/**
 * Represents a single period column in the cashflow table
 */
export type CashflowPeriod = {
  id: string;
  /** Date of the period (YYYY-MM-DD) */
  dateFrom: string;
  dateTo: string;
  /** Balance at the start of this period */
  startingBalance: number;
  /** Total income for this period */
  income: number;
  /** Total costs for this period */
  costs: number;
  /** Net change (income - costs) */
  netBalance: number;
  /** Final balance at end of period (startingBalance + netBalance) */
  finalBalance: number;
  incomeCategories: Map<CategoryType, number>;
  costsCategories: Map<CategoryType, number>;
  progressPercentage?: number;
  transactionCount?: number;
};

/**
 * Complete data structure for the cashflow table
 */
export type CashflowTableData = {
  periods: CashflowPeriod[];
  granularity: "1D" | "1W" | "1M";
  categories: {
    income: CategoryType[];
    costs: CategoryType[];
  };
};

export type CategoryFilter = {
  income: CategoryType[];
  costs: CategoryType[];
};

export type CategoryFilterSection = "income" | "costs";

export type CategoryOption = {
  value: CategoryType;
  label: string;
};

export type CategoryFilterState = {
  categoryFilter: CategoryFilter;
  setCategoryFilter: (filter: CategoryFilter) => void;
  allCategories: CategoryOption[];
  allCategoryValues: CategoryType[];
  isFiltered: boolean;
  totalSelected: number;
  totalAvailable: number;
};

export type CashflowTableCellProps = {
  value: number;
  columnIndex: number;
  dateFrom: string;
  isBold?: boolean;
  /** Optional progress percentage to display as a bar */
  progressPercentage?: number;
  /** Color mode for value display:
   * - "balance": red for negative, green for positive (Starting Balance, Net Balance)
   * - "final": red for negative only, neutral for positive/zero (Final Balance)
   * - "none": always neutral color (Income, Costs, all categories)
   * Default: "none"
   */
  colorMode?: "balance" | "final" | "none";
  /** Optional click handler. When provided, replaces the default column toggle behavior. */
  onClick?: () => void;
};

import type {
  CashFlowResponse,
  CashflowPeriod,
  CashflowTableData,
  CategoryType,
} from "../types/cashflow-table.types.ts";

/**
 * Transforms the API response from getCashFlowAndBalanceStates into table-ready data structure.
 *
 * Key transformations:
 * - Converts category arrays to Maps for efficient lookup
 * - Extracts all unique categories present in the data
 * - Renders all periods returned by the API (no padding or truncation)
 *
 * @param apiResponse - Response from getCashFlowAndBalanceStates API
 */
export function transformCashflowData(
  apiResponse: CashFlowResponse,
): CashflowTableData {
  const { cashFlowStates } = apiResponse;
  const sumArray = cashFlowStates?.sumArray ?? [];
  const { sumAggregationalGranularity } = cashFlowStates ?? {};

  // Transform API periods to table periods
  const periods: CashflowPeriod[] = sumArray.map((period, index: number) => {
    // Convert category arrays to Maps
    const incomeCategories = new Map<CategoryType, number>();
    period.incomeCategorySum?.forEach((cat) => {
      incomeCategories.set(cat.category as CategoryType, cat.amount);
    });

    const costsCategories = new Map<CategoryType, number>();
    period.costsCategorySum?.forEach((cat) => {
      costsCategories.set(cat.category as CategoryType, cat.amount);
    });

    // Calculate balances
    const startingBalance = period.startedBalance?.balance ?? 0;
    const netBalance = period.netChange;
    const finalBalance = period.finalBalance?.balance ?? 0;

    return {
      id: `period-${index}-${period.dateFrom}`,
      dateFrom: period.dateFrom,
      dateTo: period.dateTo,
      startingBalance,
      income: period.income,
      costs: period.costs,
      netBalance,
      finalBalance,
      incomeCategories,
      costsCategories,
      transactionCount: period.transactionCount,
      // Progress percentage would be calculated here if API provides planned amounts
      progressPercentage: undefined,
    };
  });

  // Extract all unique categories that have data
  const allIncomeCategories = new Set<CategoryType>();
  const allCostsCategories = new Set<CategoryType>();

  periods.forEach((period) => {
    period.incomeCategories.forEach((_, category) => {
      allIncomeCategories.add(category);
    });
    period.costsCategories.forEach((_, category) => {
      allCostsCategories.add(category);
    });
  });

  return {
    periods,
    granularity: sumAggregationalGranularity || "1M",
    categories: {
      income: Array.from(allIncomeCategories),
      costs: Array.from(allCostsCategories),
    },
  };
}

import {
  Paper,
  Table,
  TableBody,
  TableContainer,
  TableHead,
} from "@mui/material";

import { useTT } from "../../useTT.ts";
import { CashflowTableCostsCategories } from "./CashflowTableCostsCategories.tsx";
import { CashflowTableFinalBalanceRow } from "./CashflowTableFinalBalanceRow.tsx";
import { CashflowTableHeader } from "./CashflowTableHeader.tsx";
import { CashflowTableIncomeCategories } from "./CashflowTableIncomeCategories.tsx";
import { CashflowTableNetBalanceRow } from "./CashflowTableNetBalanceRow.tsx";
import { CashflowTableStartingBalanceRow } from "./CashflowTableStartingBalanceRow.tsx";

/**
 * Main cashflow table component.
 *
 * Layout (top to bottom):
 * 1. Header
 * 2. Starting Balance
 * 3. Income section header (expandable) + income categories
 * 4. Costs section header (expandable) + cost categories
 * 5. Net Balance
 * 6. Final Balance
 *
 * Features:
 * - Collapsible Income and Costs sections with totals
 * - Dynamically renders all periods returned by the API
 * - Full content height (page scrolls instead of table)
 */
export function CashflowTable() {
  const { tt } = useTT();

  return (
    <TableContainer component={Paper}>
      <Table
        sx={{ tableLayout: "fixed", borderCollapse: "separate" }}
        aria-label={tt("cashflowTable.accessibility.tableLabel")}
      >
        <TableHead>
          <CashflowTableHeader />
        </TableHead>

        <TableBody>
          <CashflowTableStartingBalanceRow />
        </TableBody>

        <TableBody>
          <CashflowTableIncomeCategories />
        </TableBody>
        <TableBody>
          <CashflowTableCostsCategories />
        </TableBody>

        <TableBody>
          <CashflowTableNetBalanceRow />
          <CashflowTableFinalBalanceRow />
        </TableBody>
      </Table>
    </TableContainer>
  );
}

import { Box, LinearProgress, TableCell } from "@mui/material";
import dayjs from "dayjs";
import { memo } from "react";

import { useTT } from "../../useTT.ts";
import { useIsColumnSelected } from "../SelectionContext.tsx";
import { useTimePeriodControls } from "../TimePeriodContext.tsx";
import { formatCashflowAmount } from "../utils/index.ts";
import type { CashflowTableCellProps } from "./types/index.ts";

/**
 * Reusable table cell component for the cashflow table.
 *
 * Performance: Memoized to prevent unnecessary re-renders. With 140+ cells
 * (7 periods x 20 categories), React.memo combined with useIsColumnSelected
 * ensures only cells whose highlight status changes re-render (typically ~14
 * cells during column highlighting: 7 cells losing highlight + 7 gaining it).
 */
function CashflowTableCellComponent({
  value,
  columnIndex,
  dateFrom,
  isBold = false,
  progressPercentage,
  colorMode,
  onClick,
}: CashflowTableCellProps) {
  const { language } = useTT();
  const isHighlighted = useIsColumnSelected(columnIndex);
  const { setPeriod } = useTimePeriodControls();

  const handleClick = onClick ?? (() => setPeriod(dayjs(dateFrom)));

  return (
    <TableCell
      onClick={handleClick}
      aria-selected={isHighlighted}
      sx={{
        textAlign: "right",
        cursor: "pointer",
        backgroundColor: "background.paper",
        borderBottom: isHighlighted ? "none" : undefined,
        borderRight: 1,
        borderRightColor: isHighlighted
          ? "custom.borderSecondary"
          : "background.paper",
        borderLeft: 1,
        borderLeftColor: isHighlighted
          ? "custom.borderSecondary"
          : "background.paper",
        fontWeight: isBold ? 600 : 400,
        color: getValueColor(colorMode, value),
        boxSizing: "border-box",
      }}
    >
      <Box>
        {formatCashflowAmount(value, language)}
        {progressPercentage !== undefined && (
          <LinearProgress
            variant="determinate"
            value={progressPercentage}
            sx={{
              mt: 0.5,
              height: 4,
              borderRadius: 1,
              backgroundColor: "action.hover",
              "& .MuiLinearProgress-bar": {
                backgroundColor:
                  progressPercentage > 100 ? "warning.main" : "primary.main",
              },
            }}
          />
        )}
      </Box>
    </TableCell>
  );
}

// Determine text color based on value
function getValueColor(
  colorMode: CashflowTableCellProps["colorMode"],
  value: number,
) {
  const mode = colorMode ?? "none";

  if (mode === "none") {
    return "text.primary";
  }

  if (mode === "final") {
    return value < 0 ? "error.main" : "text.primary";
  }

  // mode === "balance"
  if (value < 0) return "error.main";
  if (value > 0) return "success.main";
  return "text.primary";
}

export const CashflowTableCell = memo(CashflowTableCellComponent);
CashflowTableCell.displayName = "CashflowTableCell";

import { useTT } from "../../useTT.ts";
import { CashflowTableCell } from "./CashflowTableCell.tsx";
import {
  CashflowTableSummaryRow,
  CashflowTableSummaryRowLabel,
  useCashflowTable,
} from "./components/index.ts";

export function CashflowTableFinalBalanceRow() {
  const { tt } = useTT();
  const { data } = useCashflowTable();

  return (
    <CashflowTableSummaryRow>
      <CashflowTableSummaryRowLabel>
        {tt("cashflowTable.rows.finalBalance")}
      </CashflowTableSummaryRowLabel>
      {data?.periods.map((period, index) => (
        <CashflowTableCell
          key={period.id}
          value={period.finalBalance}
          columnIndex={index}
          dateFrom={period.dateFrom}
          isBold={true}
          colorMode="final"
        />
      ))}
    </CashflowTableSummaryRow>
  );
}

import { IconArrowUpRight } from "@dfp/react-icons";

import { useTT } from "../../useTT.ts";
import { CashflowTableCell } from "./CashflowTableCell.tsx";
import {
  CashflowCategory,
  CashflowCategoryDataRow,
  CashflowCategoryHeader,
  CashflowCategoryHeaderIcon,
  CashflowCategoryHeaderTitle,
  CashflowCategoryRows,
  CashflowCategoryTrigger,
  useCashflowTable,
} from "./components/index.ts";

/**
 * Income category breakdown with collapsible section.
 *
 * Structure:
 * - Income section header (with total, expandable)
 *   - Income category rows (indented)
 */
export function CashflowTableIncomeCategories() {
  const { data, categoryFilter, allCategories } = useCashflowTable();
  const { tt } = useTT();

  return (
    <CashflowCategory>
      <CashflowCategoryHeader>
        <CashflowCategoryHeaderTitle>
          <CashflowCategoryHeaderIcon sx={{ color: "success.main" }}>
            <IconArrowUpRight />
          </CashflowCategoryHeaderIcon>
          {tt("cashflowTable.rows.income")}
          <CashflowCategoryTrigger categoryType="income" />
        </CashflowCategoryHeaderTitle>

        {data?.periods.map((period, index) => (
          <CashflowTableCell
            key={period.id}
            value={period.income}
            columnIndex={index}
            dateFrom={period.dateFrom}
            isBold
            colorMode="none"
          />
        ))}
      </CashflowCategoryHeader>

      <CashflowCategoryRows>
        {categoryFilter.income.map((category) => (
          <CashflowCategoryDataRow
            key={category}
            allCategories={allCategories}
            category={category}
            direction="IN"
          />
        ))}
      </CashflowCategoryRows>
    </CashflowCategory>
  );
}

