import { Chip, Tooltip, alpha, useTheme } from "@mui/material";

import { IconAlertSquare, IconAlertTriangle } from "@dfp/react-icons";

import { useTT } from "../../../useTT.ts";
import { BalanceQuality } from "../../index.ts";
import { getQualityThemeColor } from "../cashflowQuality.config.ts";

const QUALITY_TRANSLATION_KEY = {
  CALCULATED: "chart.calculated",
  IMPORTED: "chart.imported",
  DERIVED: "chart.derived",
} as const;

const ICON_SIZE = 20;

type Props = {
  balanceQuality: BalanceQuality | null | undefined;
};

export function CashflowQualityIndicator({ balanceQuality }: Props) {
  const { tt } = useTT();
  const theme = useTheme();

  if (balanceQuality !== "DERIVED" && balanceQuality !== "CALCULATED") {
    return null;
  }

  const qualityColor = getQualityThemeColor(theme, balanceQuality);
  const chipSx = {
    width: 30,
    height: 30,
    borderColor: qualityColor,
    backgroundColor: alpha(qualityColor, 0.1),
    color: qualityColor,
    "& .MuiChip-icon": { color: qualityColor },
  };

  const icon =
    balanceQuality === "DERIVED" ? (
      <IconAlertTriangle width={ICON_SIZE} height={ICON_SIZE} />
    ) : (
      <IconAlertSquare width={ICON_SIZE} height={ICON_SIZE} />
    );

  return (
    <Tooltip title={tt(QUALITY_TRANSLATION_KEY[balanceQuality])}>
      <Chip sx={chipSx} variant="outlined" icon={icon} />
    </Tooltip>
  );
}

import { Box, CircularProgress, Paper, Stack, Typography } from "@mui/material";
import { alpha } from "@mui/material/styles";

import { useTT } from "../useTT.ts";
import { CashflowFilterControls } from "./cashflowFilterControls/index.ts";
import { CHART_HEIGHT, CashflowCharts } from "./chart/index.ts";

type CurrentBalanceChartSectionProps = {
  isInitialLoading: boolean;
  isRefetching: boolean;
};

export function CurrentBalanceChartSection({
  isInitialLoading,
  isRefetching,
}: CurrentBalanceChartSectionProps) {
  const { tt } = useTT();

  return (
    <Paper sx={{ pt: 2 }}>
      <Stack
        sx={{
          justifyContent: "space-between",
          flexDirection: "row",
          alignItems: "center",
          px: 2,
        }}
      >
        <Typography variant="h4">{tt("currentAvailableBalance")}</Typography>
        <CashflowFilterControls />
      </Stack>

      {isInitialLoading ? (
        <Box
          sx={{
            display: "flex",
            justifyContent: "center",
            alignItems: "center",
            minHeight: CHART_HEIGHT,
            mt: 2,
          }}
        >
          <CircularProgress />
        </Box>
      ) : (
        <Box sx={{ position: "relative", mt: 2 }}>
          {isRefetching && (
            <Box
              sx={{
                position: "absolute",
                inset: 0,
                display: "flex",
                justifyContent: "center",
                alignItems: "center",
                zIndex: 1,
                bgcolor: (theme) => alpha(theme.palette.background.paper, 0.6),
                backdropFilter: "blur(2px)",
                WebkitBackdropFilter: "blur(2px)",
              }}
            >
              <CircularProgress />
            </Box>
          )}

          <CashflowCharts />
        </Box>
      )}
    </Paper>
  );
}

import { type ReactNode, useMemo, useState } from "react";

import type {
  BalancePoint,
  CashFlowInterval,
  CashflowChartContextType,
  ChartViewMode,
  Interval,
  LegendData,
} from "../../types/cashflow.types.ts";
import {
  transformToBarChartData,
  transformToLineChartData,
} from "../../utils/index.ts";
import { segmentLineChartQuality } from "../line-chart/index.ts";
import {
  CashflowChartContext,
  useCashflowChartContext,
} from "./cashflowChart.context.ts";

type CashflowChartProviderProps = {
  children: ReactNode;
  data?: {
    cashFlowStates?: {
      sumArray?: CashFlowInterval[];
    };
    aggregatedBalanceValues?: Record<string, BalancePoint> | BalancePoint[];
  };
  // Interval state from parent (where the query is made)
  interval: Interval;
  setInterval: (interval: Interval) => void;
  /** Currency code for display (e.g., "EUR", "CZK") */
  currency: string;
  /** Number of bank accounts included in the query */
  bankAccountCount: number;
};

/**
 * Provider component for cashflow chart context
 * Manages view state, selection, and data transformations
 */
export function CashflowChartProvider({
  children,
  data,
  interval,
  setInterval,
  currency,
  bankAccountCount,
}: CashflowChartProviderProps) {
  const [viewMode, setViewMode] = useState<ChartViewMode>("bar");

  const cashFlowData = useMemo(
    () => data?.cashFlowStates?.sumArray || [],
    [data],
  );

  const balanceData = useMemo(() => {
    const rawBalanceData = data?.aggregatedBalanceValues;

    if (!rawBalanceData) {
      return {};
    }

    if (!Array.isArray(rawBalanceData)) {
      return rawBalanceData;
    }

    return rawBalanceData.reduce(
      (acc, balancePoint) => {
        if (balancePoint.date) {
          acc[balancePoint.date] = balancePoint;
        }
        return acc;
      },
      {} as Record<string, BalancePoint>,
    );
  }, [data]);

  const barChartData = useMemo(
    () => transformToBarChartData(cashFlowData, interval),
    [cashFlowData, interval],
  );

  const lineChartData = useMemo(
    () => transformToLineChartData(balanceData, cashFlowData),
    [balanceData, cashFlowData],
  );

  const segmentationResult = useMemo(
    () => segmentLineChartQuality(lineChartData),
    [lineChartData],
  );

  // Compute current balance from the latest balance point
  const legendData = useMemo<LegendData>(() => {
    // Get the latest balance from aggregatedBalanceValues
    const balanceEntries = Object.entries(balanceData);
    if (balanceEntries.length === 0) {
      return { currentBalance: null, currency, bankAccountCount };
    }

    // Sort by date descending to get the most recent balance
    const sortedEntries = balanceEntries.sort(([dateA], [dateB]) =>
      dateB.localeCompare(dateA),
    );
    const latestPoint = sortedEntries[0]?.[1];
    const latestBalance = latestPoint?.balance ?? null;
    const balanceQuality = latestPoint?.balanceQuality;

    return {
      currentBalance: latestBalance,
      currency,
      bankAccountCount,
      balanceQuality,
    };
  }, [balanceData, currency, bankAccountCount]);

  const contextValue = useMemo<CashflowChartContextType>(
    () => ({
      viewMode,
      setViewMode,
      interval,
      setInterval,
      legendData,
      barChartData,
      lineChartData: segmentationResult.chartData,
      lineChartSegmentKeys: {
        calculatedSegmentKeys: segmentationResult.calculatedSegmentKeys,
        importedSegmentKeys: segmentationResult.importedSegmentKeys,
        derivedSegmentKeys: segmentationResult.derivedSegmentKeys,
      },
    }),
    [
      viewMode,
      interval,
      setInterval,
      barChartData,
      segmentationResult,
      legendData,
    ],
  );

  return (
    <CashflowChartContext.Provider value={contextValue}>
      {children}
    </CashflowChartContext.Provider>
  );
}

