import dayjs from "dayjs";

import type {
  BalancePoint,
  BarChartDataPoint,
  CashFlowInterval,
  Interval,
  LineChartDataPoint,
} from "../types/cashflow.types.ts";
import { createPeriodKey, formatDateLabel } from "./cashflowFormatters.ts";
import { formatDateToISO } from "./dateUtils.ts";
import { formatPeriodLabel } from "./formatPeriodLabel.ts";

/**
 * Transform API cash flow data to bar chart data format
 * @param cashFlowData - Raw cash flow intervals from API
 * @param interval - Interval granularity for labels (1D, 1W, 1M)
 * @returns Array of bar chart data points
 */
export function transformToBarChartData(
  cashFlowData: NonNullable<CashFlowInterval>[],
  interval: Interval,
): BarChartDataPoint[] {
  return cashFlowData.map((cashFlowInterval) => {
    const periodKey = createPeriodKey(
      cashFlowInterval.dateFrom,
      cashFlowInterval.dateTo,
    );
    const periodLabel = formatPeriodLabel({
      dateFrom: cashFlowInterval.dateFrom,
      dateTo: cashFlowInterval.dateTo,
      interval,
    });

    return {
      period: periodLabel,
      periodKey,
      dateFrom: cashFlowInterval.dateFrom,
      dateTo: cashFlowInterval.dateTo,
      // Display costs as positive values for better visualization
      income: cashFlowInterval.income,
      costs: Math.abs(cashFlowInterval.costs),
      netChange: cashFlowInterval.netChange,
      // Category data for future stacking feature
      incomeCategories: cashFlowInterval.incomeCategorySum,
      costsCategories: cashFlowInterval.costsCategorySum,
      // Transaction count for debugging/analytics
      transactionCount: cashFlowInterval.transactionCount,
    };
  });
}

/**
 * Transform API balance data to line chart data format
 * @param balanceData - Map of date to balance point from API
 * @param cashFlowData - Cash flow intervals for period key mapping
 * @returns Sorted array of line chart data points
 */
export function transformToLineChartData(
  balanceData: Record<string, BalancePoint>,
  cashFlowData: CashFlowInterval[],
): LineChartDataPoint[] {
  // Convert balance map to array, filter out entries without dates, and sort by date
  const balanceArray = Object.entries(balanceData)
    .map(([_, balancePoint]) => balancePoint)
    .filter((balancePoint): balancePoint is BalancePoint & { date: string } =>
      Boolean(balancePoint.date),
    )
    .sort((a, b) => dayjs(a.date).valueOf() - dayjs(b.date).valueOf());

  // Create a lookup map for finding period keys
  const periodLookup = new Map<string, string>();
  cashFlowData.forEach((interval) => {
    const periodKey = createPeriodKey(interval.dateFrom, interval.dateTo);
    const startDate = dayjs(interval.dateFrom);
    const endDate = dayjs(interval.dateTo);

    // Map all dates within this interval to the period key
    let currentDate = startDate;
    while (
      currentDate.isBefore(endDate) ||
      currentDate.isSame(endDate, "day")
    ) {
      const dateStr = formatDateToISO(currentDate);
      periodLookup.set(dateStr, periodKey);
      currentDate = currentDate.add(1, "day");
    }
  });

  // Transform to line chart format
  return balanceArray.map((balancePoint) => {
    const dateLabel = formatDateLabel(balancePoint.date);
    const periodKey = periodLookup.get(balancePoint.date) || "";
    const timestamp = dayjs(balancePoint.date).valueOf();

    return {
      date: balancePoint.date,
      timestamp,
      dateLabel,
      balance: balancePoint.balance,
      periodKey,
      balanceQuality: balancePoint.balanceQuality ?? "CALCULATED",
    };
  });
}

import dayjs from "dayjs";
import { describe, expect, it } from "vitest";

import type {
  BalancePoint,
  CashFlowInterval,
} from "../../types/cashflow.types.ts";
import {
  transformToBarChartData,
  transformToLineChartData,
} from "../cashflowDataTransformers.ts";

describe("transformToBarChartData", () => {
  it("should return empty array for empty input", () => {
    const result = transformToBarChartData([], "1M");
    expect(result).toEqual([]);
  });

  it("should transform single interval correctly for 1M interval", () => {
    const input: CashFlowInterval[] = [
      {
        dateFrom: "2025-01-01",
        dateTo: "2025-01-31",
        income: 1000,
        costs: -500,
        netChange: 500,
      },
    ];

    const result = transformToBarChartData(input, "1M");

    expect(result).toHaveLength(1);
    expect(result[0]).toEqual({
      period: "Jan '25",
      periodKey: "2025-01-01_2025-01-31",
      dateFrom: "2025-01-01",
      dateTo: "2025-01-31",
      income: 1000,
      costs: 500, // Converted to absolute value
      netChange: 500,
      incomeCategories: undefined,
      costsCategories: undefined,
      transactionCount: undefined,
    });
  });

  it("should transform single interval correctly for 1D interval", () => {
    const input: CashFlowInterval[] = [
      {
        dateFrom: "2025-01-15",
        dateTo: "2025-01-15",
        income: 200,
        costs: -100,
        netChange: 100,
      },
    ];

    const result = transformToBarChartData(input, "1D");

    expect(result).toHaveLength(1);
    expect(result[0].period).toBe("Jan 15");
    expect(result[0].costs).toBe(100); // Absolute value
  });

  it("should transform single interval correctly for 1W interval", () => {
    const input: CashFlowInterval[] = [
      {
        dateFrom: "2025-01-01",
        dateTo: "2025-01-07",
        income: 700,
        costs: -300,
        netChange: 400,
      },
    ];

    const result = transformToBarChartData(input, "1W");

    expect(result).toHaveLength(1);
    expect(result[0].period).toBe("Jan 1-7");
    expect(result[0].costs).toBe(300);
  });

  it("should convert negative costs to absolute values", () => {
    const input: CashFlowInterval[] = [
      {
        dateFrom: "2025-01-01",
        dateTo: "2025-01-31",
        income: 1000,
        costs: -750,
        netChange: 250,
      },
    ];

    const result = transformToBarChartData(input, "1M");

    expect(result[0].costs).toBe(750);
  });

  it("should preserve category data when present", () => {
    const input: CashFlowInterval[] = [
      {
        dateFrom: "2025-01-01",
        dateTo: "2025-01-31",
        income: 1000,
        costs: -500,
        netChange: 500,
        incomeCategorySum: [
          { category: "SALARY", amount: 800 },
          { category: "FREELANCE", amount: 200 },
        ],
        costsCategorySum: [
          { category: "RENT", amount: -300 },
          { category: "FOOD", amount: -200 },
        ],
      },
    ];

    const result = transformToBarChartData(input, "1M");

    expect(result[0].incomeCategories).toEqual([
      { category: "SALARY", amount: 800 },
      { category: "FREELANCE", amount: 200 },
    ]);
    expect(result[0].costsCategories).toEqual([
      { category: "RENT", amount: -300 },
      { category: "FOOD", amount: -200 },
    ]);
  });

  it("should preserve transaction count when present", () => {
    const input: CashFlowInterval[] = [
      {
        dateFrom: "2025-01-01",
        dateTo: "2025-01-31",
        income: 1000,
        costs: -500,
        netChange: 500,
        transactionCount: 42,
      },
    ];

    const result = transformToBarChartData(input, "1M");

    expect(result[0].transactionCount).toBe(42);
  });

  it("should preserve order for multiple intervals", () => {
    const input: CashFlowInterval[] = [
      {
        dateFrom: "2025-01-01",
        dateTo: "2025-01-31",
        income: 1000,
        costs: -500,
        netChange: 500,
      },
      {
        dateFrom: "2025-02-01",
        dateTo: "2025-02-28",
        income: 1200,
        costs: -600,
        netChange: 600,
      },
      {
        dateFrom: "2025-03-01",
        dateTo: "2025-03-31",
        income: 1100,
        costs: -550,
        netChange: 550,
      },
    ];

    const result = transformToBarChartData(input, "1M");

    expect(result).toHaveLength(3);
    expect(result[0].period).toBe("Jan '25");
    expect(result[1].period).toBe("Feb '25");
    expect(result[2].period).toBe("Mar '25");
  });

  it("should handle week crossing month boundary", () => {
    const input: CashFlowInterval[] = [
      {
        dateFrom: "2025-01-29",
        dateTo: "2025-02-04",
        income: 500,
        costs: -200,
        netChange: 300,
      },
    ];

    const result = transformToBarChartData(input, "1W");

    expect(result[0].period).toBe("Jan 29 - Feb 4");
    expect(result[0].periodKey).toBe("2025-01-29_2025-02-04");
  });
});

describe("transformToLineChartData", () => {
  it("should return empty array for empty balance data", () => {
    const result = transformToLineChartData({}, []);
    expect(result).toEqual([]);
  });

  it("should transform single balance point correctly", () => {
    const balanceData: Record<string, BalancePoint> = {
      "2025-01-15": {
        balance: 5000,
        date: "2025-01-15",
      },
    };

    const cashFlowData: CashFlowInterval[] = [
      {
        dateFrom: "2025-01-01",
        dateTo: "2025-01-31",
        income: 1000,
        costs: -500,
        netChange: 500,
      },
    ];

    const result = transformToLineChartData(balanceData, cashFlowData);

    expect(result).toHaveLength(1);
    expect(result[0]).toEqual({
      date: "2025-01-15",
      timestamp: dayjs("2025-01-15").valueOf(),
      dateLabel: "Jan 15",
      balance: 5000,
      balanceQuality: "CALCULATED",
      periodKey: "2025-01-01_2025-01-31",
    });
  });

  it("should filter out balance points without dates", () => {
    const balanceData: Record<string, BalancePoint> = {
      "2025-01-15": {
        balance: 5000,
        date: "2025-01-15",
      },
      invalid: {
        balance: 3000,
        // date is undefined
      },
    };

    const cashFlowData: CashFlowInterval[] = [
      {
        dateFrom: "2025-01-01",
        dateTo: "2025-01-31",
        income: 1000,
        costs: -500,
        netChange: 500,
      },
    ];

