import { describe, expect, it } from "vitest";

import { LineChartDataPoint } from "../../../types/cashflow.types.ts";
import { segmentLineChartQuality } from "../segmentLineChartData.utils.ts";

function makePoint(
  date: string,
  balanceQuality: "CALCULATED" | "IMPORTED" | "DERIVED",
  balance = 100,
): LineChartDataPoint {
  return {
    date,
    timestamp: new Date(date).getTime(),
    dateLabel: date,
    balance,
    periodKey: "",
    balanceQuality,
  };
}

describe("segmentLineChartQuality", () => {
  it("returns empty results for empty input", () => {
    const result = segmentLineChartQuality([]);
    expect(result.chartData).toEqual([]);
    expect(result.calculatedSegmentKeys).toEqual([]);
    expect(result.importedSegmentKeys).toEqual([]);
    expect(result.derivedSegmentKeys).toEqual([]);
  });

  it("creates one segment key for a single-quality run", () => {
    const data = [
      makePoint("2024-01-01", "IMPORTED", 100),
      makePoint("2024-01-02", "IMPORTED", 110),
      makePoint("2024-01-03", "IMPORTED", 120),
    ];
    const result = segmentLineChartQuality(data);

    expect(result.importedSegmentKeys).toHaveLength(1);
    expect(result.calculatedSegmentKeys).toHaveLength(0);
    expect(result.derivedSegmentKeys).toHaveLength(0);

    const key = result.importedSegmentKeys[0];
    expect(result.chartData[0][key]).toBe(100);
    expect(result.chartData[1][key]).toBe(110);
    expect(result.chartData[2][key]).toBe(120);
  });

  it("creates separate segments on quality transition and bridges at the boundary", () => {
    const data = [
      makePoint("2024-01-01", "CALCULATED", 100),
      makePoint("2024-01-02", "CALCULATED", 110),
      makePoint("2024-01-03", "IMPORTED", 120),
      makePoint("2024-01-04", "IMPORTED", 130),
    ];
    const result = segmentLineChartQuality(data);

    expect(result.calculatedSegmentKeys).toHaveLength(1);
    expect(result.importedSegmentKeys).toHaveLength(1);

    const calcKey = result.calculatedSegmentKeys[0];
    const impKey = result.importedSegmentKeys[0];

    // CALCULATED segment covers its own points
    expect(result.chartData[0][calcKey]).toBe(100);
    expect(result.chartData[1][calcKey]).toBe(110);

    // Bridge: last CALCULATED point also gets the IMPORTED series value
    expect(result.chartData[1][impKey]).toBe(110);

    // IMPORTED segment continues from the bridge point
    expect(result.chartData[2][impKey]).toBe(120);
    expect(result.chartData[3][impKey]).toBe(130);
  });

  it("handles three consecutive quality transitions with bridges at each boundary", () => {
    const data = [
      makePoint("2024-01-01", "CALCULATED", 100),
      makePoint("2024-01-02", "IMPORTED", 110),
      makePoint("2024-01-03", "DERIVED", 120),
    ];
    const result = segmentLineChartQuality(data);

    expect(result.calculatedSegmentKeys).toHaveLength(1);
    expect(result.importedSegmentKeys).toHaveLength(1);
    expect(result.derivedSegmentKeys).toHaveLength(1);

    const calcKey = result.calculatedSegmentKeys[0];
    const impKey = result.importedSegmentKeys[0];
    const derKey = result.derivedSegmentKeys[0];

    // CALCULATED point
    expect(result.chartData[0][calcKey]).toBe(100);
    // Bridge CALCULATED→IMPORTED: point 0 gets the IMPORTED key too
    expect(result.chartData[0][impKey]).toBe(100);
    // IMPORTED point
    expect(result.chartData[1][impKey]).toBe(110);
    // Bridge IMPORTED→DERIVED: point 1 gets the DERIVED key too
    expect(result.chartData[1][derKey]).toBe(110);
    // DERIVED point
    expect(result.chartData[2][derKey]).toBe(120);
  });

  it("handles a single-day segment with bridges on both sides", () => {
    const data = [
      makePoint("2024-01-01", "IMPORTED", 100),
      makePoint("2024-01-02", "CALCULATED", 110), // single day
      makePoint("2024-01-03", "DERIVED", 120),
    ];
    const result = segmentLineChartQuality(data);

    const impKey = result.importedSegmentKeys[0];
    const calcKey = result.calculatedSegmentKeys[0];
    const derKey = result.derivedSegmentKeys[0];

    // IMPORTED segment
    expect(result.chartData[0][impKey]).toBe(100);
    // Bridge IMPORTED→CALCULATED at point 0
    expect(result.chartData[0][calcKey]).toBe(100);
    // Single CALCULATED point
    expect(result.chartData[1][calcKey]).toBe(110);
    // Bridge CALCULATED→DERIVED at point 1
    expect(result.chartData[1][derKey]).toBe(110);
    // DERIVED point
    expect(result.chartData[2][derKey]).toBe(120);
  });

  it("uses a global incrementing series index across all quality types", () => {
    const data = [
      makePoint("2024-01-01", "IMPORTED", 100),
      makePoint("2024-01-02", "DERIVED", 110),
      makePoint("2024-01-03", "CALCULATED", 120),
    ];
    const result = segmentLineChartQuality(data);

    expect(result.importedSegmentKeys[0]).toBe("importedSegment0");
    expect(result.derivedSegmentKeys[0]).toBe("derivedSegment1");
    expect(result.calculatedSegmentKeys[0]).toBe("calculatedSegment2");
  });

  it("does not mutate the input array", () => {
    const data = [
      makePoint("2024-01-01", "CALCULATED", 100),
      makePoint("2024-01-02", "IMPORTED", 110),
    ];
    const originalFirstPoint = { ...data[0] };
    segmentLineChartQuality(data);
    expect(data[0]).toEqual(originalFirstPoint);
  });
});

