import { act, render, renderHook } from "@testing-library/react";
import dayjs from "dayjs";
import isSameOrAfter from "dayjs/plugin/isSameOrAfter";
import isSameOrBefore from "dayjs/plugin/isSameOrBefore";
import isoWeek from "dayjs/plugin/isoWeek";
import { NuqsTestingAdapter } from "nuqs/adapters/testing";
import type { ReactNode } from "react";
import { beforeEach, describe, expect, it, vi } from "vitest";

import {
  type UseCashflowTimePeriodFilterResult,
  useCashflowTimePeriodFilter,
} from "./useCashflowTimePeriodFilter.ts";

dayjs.extend(isoWeek);
dayjs.extend(isSameOrAfter);
dayjs.extend(isSameOrBefore);

// Mock sessionStorage
const mockSessionStorage = (() => {
  let store: Record<string, string> = {};
  return {
    getItem: vi.fn((key: string) => store[key] || null),
    setItem: vi.fn((key: string, value: string) => {
      store[key] = value;
    }),
    removeItem: vi.fn((key: string) => {
      delete store[key];
    }),
    clear: vi.fn(() => {
      store = {};
    }),
  };
})();

Object.defineProperty(window, "sessionStorage", {
  value: mockSessionStorage,
  writable: true,
});

function createWrapper(searchParams?: Record<string, string>) {
  return function Wrapper({ children }: { children: ReactNode }) {
    return (
      <NuqsTestingAdapter searchParams={searchParams}>
        {children}
      </NuqsTestingAdapter>
    );
  };
}

describe("useCashflowTimePeriodFilter", () => {
  const defaultOptions = {
    columnCount: 6,
    maxDateRangeFrom: "2024-01-01",
    maxDateRangeTo: "2026-12-31",
    companyId: "test-company-123",
  };

  beforeEach(() => {
    mockSessionStorage.clear();
    vi.clearAllMocks();
  });

  describe("navigation - view window shifting", () => {
    it("goToPreviousPeriod in week mode shifts dateFrom one week earlier", () => {
      const wednesday = dayjs("2025-01-15"); // Wednesday

      const { result } = renderHook(
        () => useCashflowTimePeriodFilter(defaultOptions),
        { wrapper: createWrapper() },
      );

      act(() => {
        result.current.setInterval("1W");
        result.current.setPeriod(wednesday);
      });

      const dateFromBefore = result.current.dateFrom;

      act(() => {
        result.current.goToPreviousPeriod();
      });

      // dateFrom should shift one week earlier
      expect(
        dayjs(result.current.dateFrom).isBefore(dayjs(dateFromBefore)),
      ).toBe(true);
      // selectedDay should NOT change
      expect(result.current.selectedDay.format("YYYY-MM-DD")).toBe(
        "2025-01-15",
      );
    });

    it("goToNextPeriod in week mode shifts dateFrom one week later", () => {
      const wednesday = dayjs("2025-01-15");

      const { result } = renderHook(
        () => useCashflowTimePeriodFilter(defaultOptions),
        { wrapper: createWrapper() },
      );

      act(() => {
        result.current.setInterval("1W");
        result.current.setPeriod(wednesday);
      });

      const dateFromBefore = result.current.dateFrom;

      act(() => {
        result.current.goToNextPeriod();
      });

      // dateFrom should shift one week later
      expect(
        dayjs(result.current.dateFrom).isAfter(dayjs(dateFromBefore)),
      ).toBe(true);
      // selectedDay should NOT change
      expect(result.current.selectedDay.format("YYYY-MM-DD")).toBe(
        "2025-01-15",
      );

