import {
  Paper,
  Table,
  TableBody,
  TableContainer,
  TableHead,
} from "@mui/material";

import { useTT } from "../../useTT.ts";
import { CashflowTableCostsCategories } from "./CashflowTableCostsCategories.tsx";
import { CashflowTableFinalBalanceRow } from "./CashflowTableFinalBalanceRow.tsx";
import { CashflowTableHeader } from "./CashflowTableHeader.tsx";
import { CashflowTableIncomeCategories } from "./CashflowTableIncomeCategories.tsx";
import { CashflowTableNetBalanceRow } from "./CashflowTableNetBalanceRow.tsx";

/**
 * Main cashflow table component.
 *
 * Layout (top to bottom):
 * 1. Header
 * 2. Income section header (expandable) + income categories
 * 3. Costs section header (expandable) + cost categories
 * 4. Net Balance
 * 5. Final Balance
 *
 * Features:
 * - Collapsible Income and Costs sections with totals
 * - Dynamically renders all periods returned by the API
 * - Full content height (page scrolls instead of table)
 */
export function CashflowTable() {
  const { tt } = useTT();

  return (
    <TableContainer component={Paper}>
      <Table
        sx={{ tableLayout: "fixed", borderCollapse: "separate" }}
        aria-label={tt("cashflowTable.accessibility.tableLabel")}
      >
        <TableHead>
          <CashflowTableHeader />
        </TableHead>

        <TableBody>
          <CashflowTableIncomeCategories />
        </TableBody>
        <TableBody>
          <CashflowTableCostsCategories />
        </TableBody>

        <TableBody>
          <CashflowTableNetBalanceRow />
          <CashflowTableFinalBalanceRow />
        </TableBody>
      </Table>
    </TableContainer>
  );
}

import { type ReactNode, useMemo, useState } from "react";

import type {
  BalancePoint,
  CashFlowInterval,
  CashflowChartContextType,
  ChartViewMode,
  Interval,
  LegendData,
} from "../../types/cashflow.types.ts";
import {
  transformToBarChartData,
  transformToLineChartData,
} from "../../utils/index.ts";
import { segmentLineChartQuality } from "../line-chart/index.ts";
import {
  CashflowChartContext,
  useCashflowChartContext,
} from "./cashflowChart.context.ts";

type CashflowChartProviderProps = {
  children: ReactNode;
  data?: {
    cashFlowStates?: {
      sumArray?: CashFlowInterval[];
    };
    aggregatedBalanceValues?: Record<string, BalancePoint> | BalancePoint[];
    todayAggregatedBalance?: {
      balance: number;
      balanceQuality: BalancePoint["balanceQuality"];
    };
  };
  // Interval state from parent (where the query is made)
  interval: Interval;
  setInterval: (interval: Interval) => void;
  /** Currency code for display (e.g., "EUR", "CZK") */
  currency: string;
  /** Number of bank accounts included in the query */
  bankAccountCount: number;
};

/**
 * Provider component for cashflow chart context
 * Manages view state, selection, and data transformations
 */
export function CashflowChartProvider({
  children,
  data,
  interval,
  setInterval,
  currency,
  bankAccountCount,
}: CashflowChartProviderProps) {
  const [viewMode, setViewMode] = useState<ChartViewMode>("bar");

  const cashFlowData = useMemo(
    () => data?.cashFlowStates?.sumArray || [],
    [data],
  );

  const balanceData = useMemo(() => {
    const rawBalanceData = data?.aggregatedBalanceValues;

    if (!rawBalanceData) {
      return {};
    }

    if (!Array.isArray(rawBalanceData)) {
      return rawBalanceData;
    }

    return rawBalanceData.reduce(
      (acc, balancePoint) => {
        if (balancePoint.date) {
          acc[balancePoint.date] = balancePoint;
        }
        return acc;
      },
      {} as Record<string, BalancePoint>,
    );
  }, [data?.aggregatedBalanceValues]);

  const barChartData = useMemo(
    () => transformToBarChartData(cashFlowData, interval),
    [cashFlowData, interval],
  );

  const lineChartData = useMemo(
    () => transformToLineChartData(balanceData, cashFlowData),
    [balanceData, cashFlowData],
  );

  const segmentationResult = useMemo(
    () => segmentLineChartQuality(lineChartData),
    [lineChartData],
  );

  // Compute current balance from the dedicated API field
  const legendData = useMemo<LegendData>(() => {
    const todayBalance = data?.todayAggregatedBalance;

    if (!todayBalance) {
      return { currentBalance: null, currency, bankAccountCount };
    }

    return {
      currentBalance: todayBalance.balance,
      currency,
      bankAccountCount,
      balanceQuality: todayBalance.balanceQuality,
    };
  }, [data?.todayAggregatedBalance, currency, bankAccountCount]);

  const contextValue = useMemo<CashflowChartContextType>(
    () => ({
      viewMode,
      setViewMode,
      interval,
      setInterval,
      legendData,
      barChartData,
      lineChartData: segmentationResult.chartData,
      lineChartSegmentKeys: {
        calculatedSegmentKeys: segmentationResult.calculatedSegmentKeys,
        importedSegmentKeys: segmentationResult.importedSegmentKeys,
        derivedSegmentKeys: segmentationResult.derivedSegmentKeys,
      },
    }),
    [
      viewMode,
      interval,
      setInterval,
      barChartData,
      segmentationResult,
      legendData,
    ],
  );

  return (
    <CashflowChartContext.Provider value={contextValue}>
      {children}
    </CashflowChartContext.Provider>
  );
}

export { useCashflowChartContext };

