import { IconArrowUpRight } from "@dfp/react-icons";

import { useTT } from "../../useTT.ts";
import {
  CashflowCategory,
  CashflowCategoryDataRow,
  CashflowCategoryHeader,
  CashflowCategoryHeaderIcon,
  CashflowCategoryHeaderTitle,
  CashflowCategoryRows,
  CashflowCategoryTrigger,
  useCashflowTable,
} from "./components/index.ts";

/**
 * Income category breakdown with collapsible section.
 *
 * Structure:
 * - Income section header (with total, expandable)
 *   - Income category rows (indented)
 */
export function CashflowTableIncomeCategories() {
  const { data, categoryFilter, allCategories, currency } = useCashflowTable();
  const { tt } = useTT();

  return (
    <CashflowCategory>
      <CashflowCategoryHeader>
