import { describe, expect, it } from "vitest";

import type { CashFlowResponse } from "../../types/cashflow-table.types.ts";
import { transformCashflowData } from "../transformCashflowData.ts";

describe("transformCashflowData", () => {
  it("preserves final balance value and quality", () => {
    const apiResponse = {
      cashFlowStates: {
        sumAggregationalGranularity: "1M",
        sumArray: [
          {
            dateFrom: "2025-01-01",
            dateTo: "2025-01-31",
            income: 1000,
            costs: -500,
            netChange: 500,
            finalBalance: {
              balance: 1500,
              balanceQuality: "DERIVED",
            },
            incomeCategorySum: [],
            costsCategorySum: [],
          },
        ],
      },
    } as CashFlowResponse;

    const result = transformCashflowData(apiResponse);

    expect(result.periods).toHaveLength(1);
    expect(result.periods[0].finalBalance).toEqual({
      value: 1500,
      balanceQuality: "DERIVED",
    });
    expect((result.periods[0] as Record<string, unknown>).startingBalance).toBe(
      undefined,
    );
  });

  it("maps missing final balance to null", () => {
    const apiResponse = {
      cashFlowStates: {
        sumAggregationalGranularity: "1M",
        sumArray: [
          {
            dateFrom: "2025-01-01",
            dateTo: "2025-01-31",
            income: 1000,
            costs: -500,
            netChange: 500,
            incomeCategorySum: [],
            costsCategorySum: [],
          },
        ],
      },
    } as CashFlowResponse;

    const result = transformCashflowData(apiResponse);

    expect(result.periods[0].finalBalance).toBeNull();
  });
});

