import { ThemeProvider, createTheme } from "@mui/material/styles";
import { fireEvent, render, screen } from "@testing-library/react";
import dayjs from "dayjs";
import type { ReactNode } from "react";
import { describe, expect, it, vi } from "vitest";

import { SelectionProvider } from "../../../SelectionContext.tsx";
import { TimePeriodProvider } from "../../../TimePeriodContext.tsx";
import { CashflowTableSummaryValueCell } from "../CashflowTableSummaryValueCell.tsx";

vi.mock("@dfp/react-currency-amount", () => ({
  CurrencyAmount: ({ value, currency }: { value: number; currency: string }) => (
    <span>{`${value} ${currency}`}</span>
  ),
}));

vi.mock("../../../chart/components/CashflowQualityIndicator.tsx", () => ({
  CashflowQualityIndicator: ({ balanceQuality }: { balanceQuality?: string }) => (
    <span data-testid="quality-indicator">{balanceQuality ?? "none"}</span>
  ),
}));

const theme = createTheme();

function createWrapper() {
  return function Wrapper({ children }: { children: ReactNode }) {
    return (
      <ThemeProvider theme={theme}>
        <SelectionProvider selectedColumn={1}>
          <TimePeriodProvider
            timePeriodControls={{
              selectedDay: dayjs("2025-01-15"),
              setPeriod: vi.fn(),
              goToPreviousPeriod: vi.fn(),
              goToNextPeriod: vi.fn(),
              canGoToPreviousPeriod: true,
              canGoToNextPeriod: true,
              maxDateRangeFrom: dayjs("2025-01-01"),
              maxDateRangeTo: dayjs("2025-12-31"),
            }}
          >
            {children}
          </TimePeriodProvider>
        </SelectionProvider>
      </ThemeProvider>
    );
  };
}

describe("CashflowTableSummaryValueCell", () => {
  it("renders currency and quality indicator for a value", () => {
    render(
      <table>
        <tbody>
          <tr>
            <CashflowTableSummaryValueCell
              value={1234}
              currency="CZK"
              columnIndex={1}
              dateFrom="2025-01-15"
              balanceQuality="DERIVED"
            />
          </tr>
        </tbody>
      </table>,
      { wrapper: createWrapper() },
    );

    expect(screen.getByText("1234 CZK")).toBeInTheDocument();
    expect(screen.getByTestId("quality-indicator")).toHaveTextContent(
      "DERIVED",
    );
    expect(screen.getByRole("cell")).toHaveAttribute("aria-selected", "true");
  });

  it("renders empty cell content when value is missing", () => {
    render(
      <table>
        <tbody>
          <tr>
            <CashflowTableSummaryValueCell
              value={null}
              currency="CZK"
              columnIndex={1}
              dateFrom="2025-01-15"
            />
          </tr>
        </tbody>
      </table>,
      { wrapper: createWrapper() },
    );

    expect(screen.getByRole("cell")).toHaveTextContent("");
    expect(screen.queryByTestId("quality-indicator")).not.toBeInTheDocument();
  });

  it("keeps the default click behavior", () => {
    const setPeriod = vi.fn();
    const wrapper = function Wrapper({ children }: { children: ReactNode }) {
      return (
        <ThemeProvider theme={theme}>
          <SelectionProvider selectedColumn={null}>
            <TimePeriodProvider
              timePeriodControls={{
                selectedDay: dayjs("2025-01-15"),
                setPeriod,
                goToPreviousPeriod: vi.fn(),
                goToNextPeriod: vi.fn(),
                canGoToPreviousPeriod: true,
                canGoToNextPeriod: true,
                maxDateRangeFrom: dayjs("2025-01-01"),
                maxDateRangeTo: dayjs("2025-12-31"),
              }}
            >
              {children}
            </TimePeriodProvider>
          </SelectionProvider>
        </ThemeProvider>
      );
    };

    render(
      <table>
        <tbody>
          <tr>
            <CashflowTableSummaryValueCell
              value={1234}
              currency="CZK"
              columnIndex={0}
              dateFrom="2025-01-31"
            />
          </tr>
        </tbody>
      </table>,
      { wrapper },
    );

    fireEvent.click(screen.getByRole("cell"));
    expect(setPeriod).toHaveBeenCalledTimes(1);
    expect(dayjs(setPeriod.mock.calls[0][0]).format("YYYY-MM-DD")).toBe(
      "2025-01-31",
    );
  });
});

