import { render, screen } from "@testing-library/react";
import dayjs from "dayjs";
import type { ReactNode } from "react";
import { describe, expect, it } from "vitest";

import { CashflowChartProvider, useCashflowChartContext } from "../index.ts";

function Probe() {
  const { legendData } = useCashflowChartContext();
  return <pre data-testid="legend-data">{JSON.stringify(legendData)}</pre>;
}

function Wrapper({ children }: { children: ReactNode }) {
  return children;
}

describe("CashflowChartProvider legendData", () => {
  it("uses todayAggregatedBalance for current balance and quality", () => {
    render(
      <CashflowChartProvider
        data={{
          cashFlowStates: { sumArray: [] },
          todayAggregatedBalance: {
            balance: 9876,
            balanceQuality: "CALCULATED",
          },
        }}
        interval="1M"
        setInterval={() => undefined}
        currency="CZK"
        bankAccountCount={3}
      >
        <Probe />
      </CashflowChartProvider>,
      { wrapper: Wrapper },
    );

    expect(screen.getByTestId("legend-data")).toHaveTextContent(
      '"currentBalance":9876',
    );
    expect(screen.getByTestId("legend-data")).toHaveTextContent(
      '"balanceQuality":"CALCULATED"',
    );
    expect(screen.getByTestId("legend-data")).toHaveTextContent(
      '"currency":"CZK"',
    );
    expect(screen.getByTestId("legend-data")).toHaveTextContent(
      '"bankAccountCount":3',
    );
  });
});

