import { render, screen } from "@testing-library/react";
import dayjs from "dayjs";
import type { ReactNode } from "react";
import { describe, expect, it } from "vitest";

import { CashflowChartProvider, useCashflowChartContext } from "../index.ts";

function Probe() {
  const { legendData } = useCashflowChartContext();
  return <pre data-testid="legend-data">{JSON.stringify(legendData)}</pre>;
}

function Wrapper({ children }: { children: ReactNode }) {
  return children;
}

describe("CashflowChartProvider legendData", () => {
  it("uses todayAggregatedBalance for current balance and quality", () => {
    render(
      <CashflowChartProvider
        data={{
          cashFlowStates: { sumArray: [] },
          todayAggregatedBalance: {
            balance: 9876,
            balanceQuality: "CALCULATED",
          },
        }}
        interval="1M"
        setInterval={() => undefined}
        currency="CZK"
        bankAccountCount={3}
      >
        <Probe />
      </CashflowChartProvider>,
      { wrapper: Wrapper },
    );

    expect(screen.getByTestId("legend-data")).toHaveTextContent(
      '"currentBalance":9876',
    );
    expect(screen.getByTestId("legend-data")).toHaveTextContent(
      '"balanceQuality":"CALCULATED"',
    );
    expect(screen.getByTestId("legend-data")).toHaveTextContent(
      '"currency":"CZK"',
    );
    expect(screen.getByTestId("legend-data")).toHaveTextContent(
      '"bankAccountCount":3',
    );
  });
});

import { render, screen } from "@testing-library/react";
import { describe, expect, it, vi } from "vitest";

import { CurrentBalanceChartSection } from "./CurrentBalanceChartSection.tsx";

vi.mock("../useTT.ts", () => ({
  useTT: () => ({ tt: (key: string) => (key === "currentBalance" ? "Current balance" : key) }),
}));

vi.mock("./cashflowFilterControls/index.ts", () => ({
  CashflowFilterControls: () => <div data-testid="filters" />,
}));

vi.mock("./chart/index.ts", () => ({
  CHART_HEIGHT: 400,
  CashflowCharts: () => <div data-testid="charts" />,
}));

describe("CurrentBalanceChartSection", () => {
  it('renders the "Current balance" heading', () => {
    render(
      <CurrentBalanceChartSection
        isInitialLoading={false}
        isRefetching={false}
      />,
    );

    expect(screen.getByText("Current balance")).toBeInTheDocument();
  });
});

import { render, screen } from "@testing-library/react";
import { describe, expect, it, vi } from "vitest";

import { CashflowTable } from "./CashflowTable.tsx";

vi.mock("../../useTT.ts", () => ({
  useTT: () => ({
    tt: (key: string) => {
      const map: Record<string, string> = {
        "cashflowTable.accessibility.tableLabel": "Analytics table",
        "cashflowTable.rows.income": "Inflow",
        "cashflowTable.rows.costs": "Outflows",
        "cashflowTable.rows.netBalance": "Net Balance",
        "cashflowTable.rows.finalBalance": "Final Balance",
      };
      return map[key] ?? key;
    },
  }),
}));

vi.mock("./CashflowTableHeader.tsx", () => ({
  CashflowTableHeader: () => <tr><th>Header</th></tr>,
}));
vi.mock("./CashflowTableIncomeCategories.tsx", () => ({
  CashflowTableIncomeCategories: () => <tr><td>Income</td></tr>,
}));
vi.mock("./CashflowTableCostsCategories.tsx", () => ({
  CashflowTableCostsCategories: () => <tr><td>Costs</td></tr>,
}));
vi.mock("./CashflowTableNetBalanceRow.tsx", () => ({
  CashflowTableNetBalanceRow: () => <tr><td>Net Balance</td></tr>,
}));
vi.mock("./CashflowTableFinalBalanceRow.tsx", () => ({
  CashflowTableFinalBalanceRow: () => <tr><td>Final Balance</td></tr>,
}));

describe("CashflowTable", () => {
  it("does not render the Starting Balance row", () => {
    render(<CashflowTable />);

    expect(screen.queryByText("Starting Balance")).not.toBeInTheDocument();
    expect(screen.getByText("Final Balance")).toBeInTheDocument();
  });
});

import { ThemeProvider, createTheme } from "@mui/material/styles";
import { fireEvent, render, screen } from "@testing-library/react";
import dayjs from "dayjs";
import type { ReactNode } from "react";
import { describe, expect, it, vi } from "vitest";

import { SelectionProvider } from "../../../SelectionContext.tsx";
import { TimePeriodProvider } from "../../../TimePeriodContext.tsx";
import { CashflowTableSummaryValueCell } from "../CashflowTableSummaryValueCell.tsx";

vi.mock("@dfp/react-currency-amount", () => ({
  CurrencyAmount: ({ value, currency }: { value: number; currency: string }) => (
    <span>{`${value} ${currency}`}</span>
  ),
}));

vi.mock("../../../chart/components/CashflowQualityIndicator.tsx", () => ({
  CashflowQualityIndicator: ({ balanceQuality }: { balanceQuality?: string }) => (
    <span data-testid="quality-indicator">{balanceQuality ?? "none"}</span>
  ),
}));

const theme = createTheme();

function createWrapper() {
  return function Wrapper({ children }: { children: ReactNode }) {
    return (
      <ThemeProvider theme={theme}>
        <SelectionProvider selectedColumn={1}>
          <TimePeriodProvider
            timePeriodControls={{
              selectedDay: dayjs("2025-01-15"),
              setPeriod: vi.fn(),
              goToPreviousPeriod: vi.fn(),
              goToNextPeriod: vi.fn(),
              canGoToPreviousPeriod: true,
              canGoToNextPeriod: true,
              maxDateRangeFrom: dayjs("2025-01-01"),
              maxDateRangeTo: dayjs("2025-12-31"),
            }}
          >
            {children}
          </TimePeriodProvider>
        </SelectionProvider>
      </ThemeProvider>
    );
  };
}

describe("CashflowTableSummaryValueCell", () => {
  it("renders currency and quality indicator for a value", () => {
    render(
      <table>
        <tbody>
          <tr>
            <CashflowTableSummaryValueCell
              value={1234}
              currency="CZK"
              columnIndex={1}
              dateFrom="2025-01-15"
              balanceQuality="DERIVED"
            />
          </tr>
        </tbody>
      </table>,
      { wrapper: createWrapper() },
    );

    expect(screen.getByText("1234 CZK")).toBeInTheDocument();
    expect(screen.getByTestId("quality-indicator")).toHaveTextContent(
      "DERIVED",
    );
    expect(screen.getByRole("cell")).toHaveAttribute("aria-selected", "true");
  });

  it("renders empty cell content when value is missing", () => {
    render(
      <table>
        <tbody>
          <tr>
            <CashflowTableSummaryValueCell
              value={null}
              currency="CZK"
              columnIndex={1}
              dateFrom="2025-01-15"
            />
          </tr>
        </tbody>
      </table>,
      { wrapper: createWrapper() },
    );

    expect(screen.getByRole("cell")).toHaveTextContent("");
    expect(screen.queryByTestId("quality-indicator")).not.toBeInTheDocument();
  });

  it("keeps the default click behavior", () => {
    const setPeriod = vi.fn();
    const wrapper = function Wrapper({ children }: { children: ReactNode }) {
      return (
        <ThemeProvider theme={theme}>
          <SelectionProvider selectedColumn={null}>
            <TimePeriodProvider
              timePeriodControls={{
                selectedDay: dayjs("2025-01-15"),
                setPeriod,
                goToPreviousPeriod: vi.fn(),
                goToNextPeriod: vi.fn(),
                canGoToPreviousPeriod: true,
                canGoToNextPeriod: true,
                maxDateRangeFrom: dayjs("2025-01-01"),
                maxDateRangeTo: dayjs("2025-12-31"),
              }}
            >
              {children}
            </TimePeriodProvider>
          </SelectionProvider>
        </ThemeProvider>
      );
    };

    render(
      <table>
        <tbody>
          <tr>
            <CashflowTableSummaryValueCell
              value={1234}
              currency="CZK"
              columnIndex={0}
              dateFrom="2025-01-31"
            />
          </tr>
        </tbody>
      </table>,
      { wrapper },
    );

    fireEvent.click(screen.getByRole("cell"));
    expect(setPeriod).toHaveBeenCalledTimes(1);
    expect(dayjs(setPeriod.mock.calls[0][0]).format("YYYY-MM-DD")).toBe(
      "2025-01-31",
    );
  });
});

import { Chip, ThemeProvider, createTheme } from "@mui/material";
import { render, screen, waitFor } from "@testing-library/react";
import { fireEvent } from "@testing-library/react";
import type { ReactNode } from "react";
import { describe, expect, it, vi } from "vitest";

import { CashflowQualityIndicator } from "../CashflowQualityIndicator.tsx";

const translations: Record<string, string> = {
  "chart.qualityTooltipDerived":
    "Estimated balance. The bank did not provide the balance for this day. The most recent available balance is used instead.",
  "chart.qualityTooltipCalculated":
    "Calculated balance. No bank balance is available for this period. The balance is calculated from transaction history and may differ from the actual bank balance.",
};

vi.mock("../../../useTT.ts", () => ({
  useTT: () => ({
    tt: (key: string) => translations[key] ?? key,
  }),
}));

const theme = createTheme();

function renderWithTheme(node: ReactNode) {
  return render(<ThemeProvider theme={theme}>{node}</ThemeProvider>);
}

describe("CashflowQualityIndicator", () => {
  it("renders nothing for imported balances", () => {
    const { container } = renderWithTheme(
      <CashflowQualityIndicator balanceQuality="IMPORTED" />,
    );

    expect(container).toBeEmptyDOMElement();
  });

  it("shows the derived tooltip text", async () => {
    const { container } = renderWithTheme(
      <CashflowQualityIndicator balanceQuality="DERIVED" />,
    );

    const chip = container.querySelector(".MuiChip-root");
    expect(chip).toBeTruthy();

    fireEvent.mouseOver(chip as Element);

    await waitFor(() => {
      expect(
        screen.getByText(translations["chart.qualityTooltipDerived"]),
      ).toBeInTheDocument();
    });
  });

  it("shows the calculated tooltip text", async () => {
    const { container } = renderWithTheme(
      <CashflowQualityIndicator balanceQuality="CALCULATED" />,
    );

    const chip = container.querySelector(".MuiChip-root");
    expect(chip).toBeTruthy();

    fireEvent.mouseOver(chip as Element);

    await waitFor(() => {
      expect(
        screen.getByText(translations["chart.qualityTooltipCalculated"]),
      ).toBeInTheDocument();
    });
  });
});

