import { IconArrowDownRight } from "@dfp/react-icons";

import { useTT } from "../../useTT.ts";
import {
  CashflowCategory,
  CashflowTableSummaryValueCell,
  CashflowCategoryDataRow,
  CashflowCategoryHeader,
  CashflowCategoryHeaderIcon,
  CashflowCategoryHeaderTitle,
  CashflowCategoryRows,
  CashflowCategoryTrigger,
  useCashflowTable,
} from "./components/index.ts";

/**
 * Costs category breakdown with collapsible section.
 *
 * Structure:
 * - Costs section header (with total, expandable)
 *   - Cost category rows (indented)
 */
export function CashflowTableCostsCategories() {
  const { data, categoryFilter, allCategories, currency } = useCashflowTable();
  const { tt } = useTT();

  return (
    <CashflowCategory>
      <CashflowCategoryHeader>
        <CashflowCategoryHeaderTitle>
          <CashflowCategoryHeaderIcon sx={{ color: "error.main" }}>
            <IconArrowDownRight />
          </CashflowCategoryHeaderIcon>
          {tt("cashflowTable.rows.costs")}
          <CashflowCategoryTrigger categoryType="costs" />
        </CashflowCategoryHeaderTitle>

        {data?.periods.map((period, index) => (
          <CashflowTableSummaryValueCell
            key={period.id}
            value={period.costs}
            currency={currency}
            columnIndex={index}
            dateFrom={period.dateFrom}
            isBold
            colorMode="none"
          />
        ))}
      </CashflowCategoryHeader>

      <CashflowCategoryRows>
        {categoryFilter.costs.map((category) => (
          <CashflowCategoryDataRow
            key={category}
            allCategories={allCategories}
            category={category}
            direction="OUT"
          />
        ))}
      </CashflowCategoryRows>
    </CashflowCategory>
  );
}

